$files = @(
  @{ path = "packages/mcp/src/index.ts"; b64 = "" }
  @{ path = "packages/mcp/src/types.ts"; b64 = "" }
  @{ path = "packages/mcp/src/tools.ts"; b64 = "" }
  @{ path = "packages/mcp/test/mcp.test.ts"; b64 = "" }
  @{ path = "packages/mcp/examples/server-demo.ts"; b64 = "" }
  @{ path = "packages/mcp/examples/approval-demo.ts"; b64 = "" }
  @{ path = "packages/mcp/package.json"; b64 = "" }
  @{ path = "packages/mcp/tsconfig.json"; b64 = "" }
  @{ path = "packages/mcp/README.md"; b64 = "" }
)
foreach ($file in $files) {
    $target = [System.IO.Path]::GetFullPath([System.IO.Path]::Combine($PWD, $file.path))
    $dir = [System.IO.Path]::GetDirectoryName($target)
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    [System.IO.File]::WriteAllBytes($target, [System.Convert]::FromBase64String($file.b64))
    Write-Host "wrote $($file.path)"
}
Write-Host "Done."
